div.t-attf-style:
text-align:center;padding:10px 6px;border-radius:var(--r-md);
                                    border:1px solid #{(wo_rework or 0) > 0 and 'rgba(232,85,85,.3)' or 'var(--border)'};
                                    background:#{(wo_rework or 0) > 0 and 'var(--red-bg)' or 'var(--surface)'}

height:100%;border-radius:2px;
                                            width:#{min(mosque.overall_kpi or 0, 100)}%;
                                            background:#{(mosque.overall_kpi or 0) >= 70 and 'var(--green)' or (mosque.overall_kpi or 0) >= 50 and 'var(--gold)' or 'var(--red)'}

padding:14px 16px;border-radius:var(--r-md);
                               margin-bottom:12px;border:1px solid;
                               background:#{wo.grade in ['a','b'] and 'var(--green-bg)' or 'var(--red-bg)'};
                               border-color:#{wo.grade in ['a','b'] and 'rgba(46,204,138,.2)' or 'rgba(232,85,85,.2)'}

width:36px;height:36px;border-radius:50%;flex-shrink:0;
                                  display:flex;align-items:center;justify-content:center;
                                  font-size:16px;
                                  background:#{test.result == 'pass' and 'var(--green-bg)' or test.result == 'fail' and 'var(--red-bg)' or 'var(--surface3)'}
